{"content": "     1|"use client";
     2|
     3|import { useState, useEffect, useRef } from "react";
     4|import content from "@/content/menu-content.json";
     5|
     6|// ─── CONTENT ────────────────────────────────────────────────────────────────
     7|
     8|const SITE = content.site;
     9|const PLANS = content.plans;
    10|const STEPS = content.steps;
    11|const FAQS = content.faqs;
    12|const CHEF = content.chef;
    13|const EXTRAS = content.extras;
    14|const CATALOG = content.catalog;
    15|
    16|// Current week rotation — in production these come from Supabase
    17|const CURRENT_WEEK = {
    18|  label: "Semana del 13 al 18 mayo",
    19|  options: [
    20|    CATALOG.find((p) => p.id === "bolognese")!,
    21|    CATALOG.find((p) => p.id === "pollo-pepitoria")!,
    22|    CATALOG.find((p) => p.id === "lentejas")!,
    23|  ],
    24|  extra: EXTRAS.find((e) => e.id === "crema-zapallo")!,
    25|};
    26|
    27|// ─── UTILS ───────────────────────────────────────────────────────────────────
    28|
    29|const fmt = (n: number) => n.toLocaleString("es-PY");
    30|
    31|// ─── COMPONENTS ──────────────────────────────────────────────────────────────
    32|
    33|function Navbar() {
    34|  const [scrolled, setScrolled] = useState(false);
    35|  const [open, setOpen] = useState(false);
    36|
    37|  useEffect(() => {
    38|    const onScroll = () => setScrolled(window.scrollY > 40);
    39|    window.addEventListener("scroll", onScroll);
    40|    return () => window.removeEventListener("scroll", onScroll);
    41|  }, []);
    42|
    43|  return (
    44|    <nav
    45|      style={{
    46|        position: "fixed", top: 0, left: 0, right: 0, zIndex: 50,
    47|        transition: "all 0.3s ease",
    48|        backgroundColor: scrolled ? "#faf7f2" : "transparent",
    49|        boxShadow: scrolled ? "0 2px 16px rgba(0,0,0,0.08)" : "none",
    50|      }}
    51|    >
    52|      <div
    53|        style={{
    54|          maxWidth: 1100, margin: "0 auto", padding: "0 24px",
    55|          display: "flex", alignItems: "center", justifyContent: "space-between",
    56|          height: scrolled ? 64 : 80, transition: "height 0.3s ease",
    57|        }}
    58|      >
    59|        {/* Logo */}
    60|        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
    61|          <div
    62|            style={{
    63|              width: 36, height: 36, borderRadius: 10,
    64|              backgroundColor: "#2d5a3d",
    65|              display: "flex", alignItems: "center", justifyContent: "center",
    66|              fontSize: 18,
    67|            }}
    68|          >
    69|            🍲
    70|          </div>
    71|          <span
    72|            style={{
    73|              fontFamily: "var(--font-playfair)", fontSize: 22,
    74|              fontWeight: 700, color: "#2d5a3d", letterSpacing: "-0.5px",
    75|            }}
    76|          >
    77|            {SITE.name}
    78|          </span>
    79|          <span
    80|            style={{
    81|              fontFamily: "var(--font-lato)", fontSize: 12, color: "#6b6b6b",
    82|              borderLeft: "1px solid #e8e4dc", paddingLeft: 10, marginLeft: 4,
    83|            }}
    84|          >
    85|            {SITE.tagline}
    86|          </span>
    87|        </div>
    88|
    89|        {/* Desktop nav */}
    90|        <div style={{ display: "flex", alignItems: "center", gap: 32 }} className="hide-mobile">
    91|          {["Cómo funciona", "Menú", "Planes", "Chef", "FAQ"].map((item) => (
    92|            <a
    93|              key={item}
    94|              href={`#${item.toLowerCase().replace(/ /g, "-")}`}
    95|              style={{
    96|                fontFamily: "var(--font-lato)", fontSize: 14, fontWeight: 400,
    97|                color: "#2a2a2a", textDecoration: "none", letterSpacing: "0.3px",
    98|              }}
    99|            >
   100|              {item}
   101|            </a>
   102|          ))}
   103|          <a
   104|            href={`https://wa.me/${SITE.whatsapp}?text=Hola!%20Quiero%20saber%20más%20sobre%20Prep.`}
   105|            style={{
   106|              backgroundColor: "#2d5a3d", color: "#faf7f2",
   107|              padding: "10px 22px", borderRadius: 8,
   108|              fontFamily: "var(--font-lato)", fontSize: 14, fontWeight: 700,
   109|              textDecoration: "none", letterSpacing: "0.3px",
   110|              transition: "background-color 0.2s",
   111|            }}
   112|            onMouseEnter={(e) => ((e.target as HTMLElement).style.backgroundColor = "#3d7a52")}
   113|            onMouseLeave={(e) => ((e.target as HTMLElement).style.backgroundColor = "#2d5a3d")}
   114|          >
   115|            Escribir por WhatsApp
   116|          </a>
   117|        </div>
   118|
   119|        <button
   120|          className="show-mobile"
   121|          onClick={() => setOpen(!open)}
   122|          style={{
   123|            background: "none", border: "none", cursor: "pointer",
   124|            padding: 8, fontSize: 24,
   125|          }}
   126|        >
   127|          {open ? "✕" : "☰"}
   128|        </button>
   129|      </div>
   130|
   131|      {open && (
   132|        <div style={{ backgroundColor: "#faf7f2", borderTop: "1px solid #e8e4dc", padding: "16px 24px 24px" }} className="show-mobile">
   133|          {["Cómo funciona", "Menú", "Planes", "Chef", "FAQ"].map((item) => (
   134|            <a
   135|              key={item}
   136|              href={`#${item.toLowerCase().replace(/ /g, "-")}`}
   137|              onClick={() => setOpen(false)}
   138|              style={{
   139|                display: "block", padding: "12px 0",
   140|                fontFamily: "var(--font-lato)", fontSize: 16, color: "#2a2a2a",
   141|                textDecoration: "none", borderBottom: "1px solid #e8e4dc",
   142|              }}
   143|            >
   144|              {item}
   145|            </a>
   146|          ))}
   147|          <a
   148|            href={`https://wa.me/${SITE.whatsapp}?text=Hola!%20Quiero%20saber%20más%20sobre%20Prep.`}
   149|            style={{
   150|              display: "block", marginTop: 16, backgroundColor: "#2d5a3d",
   151|              color: "#faf7f2", padding: "12px 22px", borderRadius: 8,
   152|              fontFamily: "var(--font-lato)", fontSize: 14, fontWeight: 700,
   153|              textDecoration: "none", textAlign: "center",
   154|            }}
   155|          >
   156|            Escribir por WhatsApp
   157|          </a>
   158|        </div>
   159|      )}
   160|
   161|      <style>{`
   162|        @media (min-width: 768px) { .show-mobile { display: none !important; } }
   163|        @media (max-width: 767px) { .hide-mobile { display: none !important; } }
   164|      `}</style>
   165|    </nav>
   166|  );
   167|}
   168|
   169|function Hero() {
   170|  return (
   171|    <section
   172|      style={{
   173|        minHeight: "100vh", display: "flex", alignItems: "center",
   174|        backgroundColor: "#faf7f2", position: "relative",
   175|        overflow: "hidden", paddingTop: 80,
   176|      }}
   177|    >
   178|      {/* Decorative circles */}
   179|      <div style={{ position: "absolute", top: -120, right: -120, width: 480, height: 480, borderRadius: "50%", backgroundColor: "#e8f0e9", zIndex: 0 }} />
   180|      <div style={{ position: "absolute", bottom: -80, left: -60, width: 280, height: 280, borderRadius: "50%", backgroundColor: "#f5ede4", zIndex: 0 }} />
   181|
   182|      <div
   183|        style={{
   184|          maxWidth: 1100, margin: "0 auto", padding: "0 24px",
   185|          display: "grid", gridTemplateColumns: "1fr 1fr", gap: 60,
   186|          alignItems: "center", position: "relative", zIndex: 1,
   187|        }}
   188|        className="hero-grid"
   189|      >
   190|        {/* Text */}
   191|        <div>
   192|          <div
   193|            style={{
   194|              display: "inline-flex", alignItems: "center", gap: 8,
   195|              backgroundColor: "#e8f0e9", borderRadius: 999, padding: "6px 16px",
   196|              marginBottom: 28, opacity: 0,
   197|              animation: "fadeInUp 0.6s ease-out 0.1s forwards",
   198|            }}
   199|          >
   200|            <span style={{ fontSize: 14, color: "#2d5a3d" }}>
   201|              🍲 Menú semanal rotativo de Edu Cano
   202|            </span>
   203|          </div>
   204|
   205|          <h1
   206|            style={{
   207|              fontFamily: "var(--font-playfair)",
   208|              fontSize: "clamp(40px, 5vw, 64px)", fontWeight: 700,
   209|              color: "#2a2a2a", lineHeight: 1.1, marginBottom: 24, opacity: 0,
   210|              animation: "fadeInUp 0.7s ease-out 0.2s forwards",
   211|            }}
   212|          >
   213|            Tu semana,{" "}
   214|            <span style={{ color: "#2d5a3d" }}>organizada</span>
   215|            <br />desde el freezer
   216|          </h1>
   217|
   218|          <p
   219|            style={{
   220|              fontFamily: "var(--font-lato)", fontSize: 18, color: "#6b6b6b",
   221|              lineHeight: 1.7, marginBottom: 36, maxWidth: 440, opacity: 0,
   222|              animation: "fadeInUp 0.7s ease-out 0.35s forwards",
   223|            }}
   224|          >
   225|            Cocinamos 3 opciones cada semana con técnica profesional.
   226|            Sellamos al vacío. Te lo llevamos el domingo. Vos solo calentás.
   227|          </p>
   228|
   229|          <div style={{ display: "flex", gap: 16, flexWrap: "wrap", opacity: 0, animation: "fadeInUp 0.7s ease-out 0.5s forwards" }}>
   230|            <a
   231|              href="#menu"
   232|              style={{
   233|                backgroundColor: "#2d5a3d", color: "#faf7f2",
   234|                padding: "14px 32px", borderRadius: 10,
   235|                fontFamily: "var(--font-lato)", fontSize: 15, fontWeight: 700,
   236|                textDecoration: "none", letterSpacing: "0.3px",
   237|                boxShadow: "0 4px 20px rgba(45, 90, 61, 0.3)",
   238|                transition: "all 0.2s",
   239|              }}
   240|              onMouseEnter={(e) => {
   241|                (e.target as HTMLElement).style.backgroundColor = "#3d7a52";
   242|                (e.target as HTMLElement).style.transform = "translateY(-2px)";
   243|              }}
   244|              onMouseLeave={(e) => {
   245|                (e.target as HTMLElement).style.backgroundColor = "#2d5a3d";
   246|                (e.target as HTMLElement).style.transform = "translateY(0)";
   247|              }}
   248|            >
   249|              Ver menú de esta semana →
   250|            </a>
   251|            <a
   252|              href="#como-funciona"
   253|              style={{
   254|                backgroundColor: "transparent", color: "#2d5a3d",
   255|                padding: "14px 32px", borderRadius: 10,
   256|                fontFamily: "var(--font-lato)", fontSize: 15, fontWeight: 700,
   257|                textDecoration: "none", border: "2px solid #2d5a3d",
   258|                transition: "all 0.2s",
   259|              }}
   260|              onMouseEnter={(e) => { (e.target as HTMLElement).style.backgroundColor = "#e8f0e9"; }}
   261|              onMouseLeave={(e) => { (e.target as HTMLElement).style.backgroundColor = "transparent"; }}
   262|            >
   263|              ¿Cómo funciona?
   264|            </a>
   265|          </div>
   266|
   267|          <div style={{ marginTop: 40, display: "flex", gap: 32, opacity: 0, animation: "fadeInUp 0.7s ease-out 0.6s forwards" }}>
   268|            {[
   269|              { num: "25", label: "Platos en el catálogo" },
   270|              { num: SITE.delivery_days.split(" ")[0], label: "Entrega domingos" },
   271|              { num: "30 días", label: "En tu freezer" },
   272|            ].map((stat) => (
   273|              <div key={stat.label}>
   274|                <div style={{ fontFamily: "var(--font-playfair)", fontSize: 24, fontWeight: 700, color: "#2d5a3d" }}>
   275|                  {stat.num}
   276|                </div>
   277|                <div style={{ fontFamily: "var(--font-lato)", fontSize: 12, color: "#6b6b6b", marginTop: 2 }}>
   278|                  {stat.label}
   279|                </div>
   280|              </div>
   281|            ))}
   282|          </div>
   283|        </div>
   284|
   285|        {/* Visual — fridge mockup */}
   286|        <div style={{ position: "relative", opacity: 0, animation: "fadeInUp 0.9s ease-out 0.4s forwards" }} className="hide-mobile">
   287|          <div style={{ backgroundColor: "#fff", borderRadius: 24, padding: 32, boxShadow: "0 8px 40px rgba(0,0,0,0.08)", position: "relative" }}>
   288|            <div style={{ backgroundColor: "#faf7f2", borderRadius: 16, overflow: "hidden", border: "1px solid #e8e4dc" }}>
   289|              <div style={{ backgroundColor: "#2d5a3d", padding: "12px 20px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
   290|                <span style={{ fontFamily: "var(--font-lato)", fontSize: 12, color: "#faf7f2", fontWeight: 700, letterSpacing: "1px" }}>
   291|                  TU FREEZER — {CURRENT_WEEK.label.toUpperCase()}
   292|                </span>
   293|                <span style={{ fontSize: 16 }}>✅</span>
   294|              </div>
   295|              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, padding: 20 }}>
   296|                {CURRENT_WEEK.options.map((plate, i) => {
   297|                  const tags: Record<string, { bg: string; text: string }> = {
   298|                    carne: { bg: "#fde8c8", text: "🥩" },
   299|                    pollo: { bg: "#d4edda", text: "🐔" },
   300|                    vegetarian: { bg: "#fff3cd", text: "🥬" },
   301|                  };
   302|                  const t = tags[plate.protein] || tags.vegetarian;
   303|                  return (
   304|                    <div key={plate.id} style={{ backgroundColor: t.bg, borderRadius: 12, padding: "14px 12px", textAlign: "center" }}>
   305|                      <div style={{ fontSize: 20, marginBottom: 4 }}>{t.text}</div>
   306|                      <div style={{ fontFamily: "var(--font-lato)", fontSize: 10, fontWeight: 700, color: "#2a2a2a", lineHeight: 1.3 }}>
   307|                        {plate.name.length > 30 ? plate.name.substring(0, 28) + "…" : plate.name}
   308|                      </div>
   309|                      <div style={{ fontFamily: "var(--font-lato)", fontSize: 9, color: "#6b6b6b", marginTop: 2 }}>
   310|                        Gs. {fmt(plate.price_gsc)}
   311|                      </div>
   312|                    </div>
   313|                  );
   314|                })}
   315|              </div>
   316|            </div>
   317|            <div style={{ position: "absolute", bottom: -20, left: -20, backgroundColor: "#fff", borderRadius: 14, padding: "12px 16px", boxShadow: "0 4px 20px rgba(0,0,0,0.1)", display: "flex", alignItems: "center", gap: 10, animation: "float 4s ease-in-out infinite" }}>
   318|              <span style={{ fontSize: 28 }}>📦</span>
   319|              <div>
   320|                <div style={{ fontFamily: "var(--font-lato)", fontSize: 11, color: "#6b6b6b" }}>Sellado al vacío</div>
   321|                <div style={{ fontFamily: "var(--font-lato)", fontSize: 13, fontWeight: 700, color: "#2d5a3d" }}>Cadena de frío</div>
   322|              </div>
   323|            </div>
   324|          </div>
   325|        </div>
   326|      </div>
   327|
   328|      <style>{`
   329|        @keyframes fadeInUp { from { opacity: 0; transform: translateY(24px); } to { opacity: 1; transform: translateY(0); } }
   330|        @keyframes float { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-8px); } }
   331|        @media (max-width: 900px) { .hero-grid { grid-template-columns: 1fr !important; } }
   332|      `}</style>
   333|    </section>
   334|  );
   335|}
   336|
   337|function ComoFunciona() {
   338|  const ref = useRef<HTMLDivElement>(null);
   339|  const [visible, setVisible] = useState(false);
   340|
   341|  useEffect(() => {
   342|    const obs = new IntersectionObserver(([e]) => e.isIntersecting && setVisible(true), { threshold: 0.2 });
   343|    if (ref.current) obs.observe(ref.current);
   344|    return () => obs.disconnect();
   345|  }, []);
   346|
   347|  return (
   348|    <section id="como-funciona" ref={ref} style={{ padding: "100px 24px", backgroundColor: "#fff" }}>
   349|      <div style={{ maxWidth: 1100, margin: "0 auto" }}>
   350|        <div style={{ textAlign: "center", marginBottom: 64 }}>
   351|          <div style={{ fontFamily: "var(--font-lato)", fontSize: 12, fontWeight: 700, color: "#c4703b", letterSpacing: "2px", textTransform: "uppercase", marginBottom: 12 }}>
   352|            Simple y claro
   353|          </div>
   354|          <h2 style={{ fontFamily: "var(--font-playfair)", fontSize: "clamp(32px, 4vw, 48px)", fontWeight: 700, color: "#2a2a2a", lineHeight: 1.15 }}>
   355|            Así funciona
   356|          </h2>
   357|        </div>
   358|
   359|        <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 32 }} className="steps-grid">
   360|          {STEPS.map((step, i) => (
   361|            <div
   362|              key={step.number}
   363|              style={{
   364|                opacity: visible ? 1 : 0, transform: visible ? "translateY(0)" : "translateY(24px)",
   365|                transition: `all 0.5s ease ${i * 0.12}s`,
   366|              }}
   367|            >
   368|              <div style={{ fontFamily: "var(--font-playfair)", fontSize: 52, fontWeight: 700, color: "#e8f0e9", lineHeight: 1, marginBottom: 16 }}>
   369|                {step.number}
   370|              </div>
   371|              <h3 style={{ fontFamily: "var(--font-playfair)", fontSize: 20, fontWeight: 700, color: "#2a2a2a", marginBottom: 10 }}>
   372|                {step.title}
   373|              </h3>
   374|              <p style={{ fontFamily: "var(--font-lato)", fontSize: 14, color: "#6b6b6b", lineHeight: 1.65 }}>
   375|                {step.description}
   376|              </p>
   377|            </div>
   378|          ))}
   379|        </div>
   380|
   381|        <style>{`
   382|          @media (max-width: 900px) { .steps-grid { grid-template-columns: 1fr 1fr !important; } }
   383|          @media (max-width: 600px) { .steps-grid { grid-template-columns: 1fr !important; } }
   384|        `}</style>
   385|      </div>
   386|    </section>
   387|  );
   388|}
   389|
   390|function MenuSection() {
   391|  const ref = useRef<HTMLDivElement>(null);
   392|  const [visible, setVisible] = useState(false);
   393|
   394|  useEffect(() => {
   395|    const obs = new IntersectionObserver(([e]) => e.isIntersecting && setVisible(true), { threshold: 0.1 });
   396|    if (ref.current) obs.observe(ref.current);
   397|    return () => obs.disconnect();
   398|  }, []);
   399|
   400|  const stabilityLabel = (n: number) => "🧊".repeat(n);
   401|
   402|  return (
   403|    <section id="menu" ref={ref} style={{ padding: "100px 24px", backgroundColor: "#faf7f2" }}>
   404|      <div style={{ maxWidth: 1100, margin: "0 auto" }}>
   405|        <div style={{ textAlign: "center", marginBottom: 64 }}>
   406|          <div style={{ fontFamily: "var(--font-lato)", fontSize: 12, fontWeight: 700, color: "#c4703b", letterSpacing: "2px", textTransform: "uppercase", marginBottom: 12 }}>
   407|            Esta semana
   408|          </div>
   409|          <h2 style={{ fontFamily: "var(--font-playfair)", fontSize: "clamp(32px, 4vw, 48px)", fontWeight: 700, color: "#2a2a2a", lineHeight: 1.15, marginBottom: 8 }}>
   410|            {CURRENT_WEEK.label}
   411|          </h2>
   412|          <p style={{ fontFamily: "var(--font-lato)", fontSize: 15, color: "#6b6b6b" }}>
   413|            Pedidos hasta el {SITE.order_cutoff} · Entrega {SITE.delivery_days}
   414|          </p>
   415|        </div>
   416|
   417|        {/* Options A/B/C */}
   418|        <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 24, marginBottom: 32 }} className="menu-grid">
   419|          {CURRENT_WEEK.options.map((plate, i) => {
   420|            const label = ["A", "B", "C"][i];
   421|            const colors = ["#e8f0e9", "#fde8c8", "#d4edda"];
   422|            const tagColors = ["#2d5a3d", "#c4703b", "#5a8a5a"];
   423|            return (
   424|              <div
   425|                key={plate.id}
   426|                style={{
   427|                  backgroundColor: "#fff", borderRadius: 20,
   428|                  border: "1px solid #e8e4dc", padding: "28px 24px",
   429|                  opacity: visible ? 1 : 0, transform: visible ? "translateY(0)" : "translateY(20px)",
   430|                  transition: `all 0.5s ease ${i * 0.12}s`,
   431|                }}
   432|              >
   433|                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 16 }}>
   434|                  <div style={{ backgroundColor: colors[i], borderRadius: 8, padding: "4px 12px" }}>
   435|                    <span style={{ fontFamily: "var(--font-playfair)", fontSize: 22, fontWeight: 700, color: tagColors[i] }}>
   436|                      {label}
   437|                    </span>
   438|                  </div>
   439|                  <span style={{ fontSize: 18 }}>{stabilityLabel(plate.stability)}</span>
   440|                </div>
   441|                <h3 style={{ fontFamily: "var(--font-playfair)", fontSize: 18, fontWeight: 700, color: "#2a2a2a", marginBottom: 8, lineHeight: 1.3 }}>
   442|                  {plate.name}
   443|                </h3>
   444|                <p style={{ fontFamily: "var(--font-lato)", fontSize: 13, color: "#6b6b6b", lineHeight: 1.6, marginBottom: 16 }}>
   445|                  {plate.description}
   446|                </p>
   447|                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", borderTop: "1px solid #e8e4dc", paddingTop: 16 }}>
   448|                  <span style={{ fontFamily: "var(--font-playfair)", fontSize: 24, fontWeight: 700, color: "#2d5a3d" }}>
   449|                    Gs. {fmt(plate.price_gsc)}
   450|                  </span>
   451|                  <span style={{ fontFamily: "var(--font-lato)", fontSize: 11, color: "#6b6b6b", textTransform: "uppercase", letterSpacing: "1px" }}>
   452|                    {plate.protein}
   453|                  </span>
   454|                </div>
   455|              </div>
   456|            );
   457|          })}
   458|        </div>
   459|
   460|        {/* Extra */}
   461|        <div
