function ChefSection({ onCatalog }: { onCatalog: () => void }) {
  const ref = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => e.isIntersecting && setVisible(true), { threshold: 0.2 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);

  const catalogCounts = CATALOG.reduce<Record<string, number>>((acc, p) => {
    if (p.category === "soup") acc["Sopas y legumbres"] = (acc["Sopas y legumbres"] || 0) + 1;
    else if (p.protein === "carne") acc["Carnes y braseados"] = (acc["Carnes y braseados"] || 0) + 1;
    else if (p.protein === "pollo") acc["Ave y pollo"] = (acc["Ave y pollo"] || 0) + 1;
    else acc["Vegetarianos"] = (acc["Vegetarianos"] || 0) + 1;
    return acc;
  }, {});

  return (
    <section id="chef" ref={ref} style={{ padding: "100px 24px", backgroundColor: "#2d5a3d" }}>
      <div style={{ maxWidth: 900, margin: "0 auto", display: "grid", gridTemplateColumns: "1fr 1fr", gap: 60, alignItems: "center" }} className="chef-grid">
        <div style={{ opacity: visible ? 1 : 0, transform: visible ? "translateX(0)" : "translateX(-24px)", transition: "all 0.6s ease" }}>
